import java.util.*;
import java.util.Base64;

public class Q4 {

    record ValidationResult(boolean valid, List<String> errors) {
        static ValidationResult ok() { return new ValidationResult(true, List.of()); }
        @SafeVarargs
        static ValidationResult fail(String... errs) { return new ValidationResult(false, Arrays.asList(errs)); }
    }

    static String createToken(String sub, long expEpochSec, String role, boolean validSig) {
        String payload = "sub=" + sub + ",exp=" + expEpochSec + ",role=" + role;
        String b64 = Base64.getEncoder().encodeToString(payload.getBytes());
        int sig = validSig ? payload.hashCode() : 12345;
        return b64 + "." + sig;
    }

    static ValidationResult validate(String token, long nowEpoch, Set<String> requiredClaims) {
        String[] parts = token.split("\\.");
        if (parts.length != 2) return ValidationResult.fail("MALFORMED_TOKEN");

        String payload;
        try {
            payload = new String(Base64.getDecoder().decode(parts[0]));
        } catch (Exception e) {
            return ValidationResult.fail("INVALID_BASE64");
        }

        // Parse claims
        Map<String, String> claims = new HashMap<>();
        for (String pair : payload.split(",")) {
            String[] kv = pair.split("=", 2);
            if (kv.length == 2) claims.put(kv[0], kv[1]);
        }

        List<String> errors = new ArrayList<>();

        // Verify signature
        int expectedSig = payload.hashCode();
        int actualSig;
        try { actualSig = Integer.parseInt(parts[1]); }
        catch (NumberFormatException e) { actualSig = -1; }
        if (actualSig != expectedSig) errors.add("INVALID_SIGNATURE");

        // Check expiry
        if (claims.containsKey("exp")) {
            long exp = Long.parseLong(claims.get("exp"));
            if (exp < nowEpoch) errors.add("TOKEN_EXPIRED");
        } else {
            errors.add("MISSING_EXP");
        }

        // Check required claims
        for (String req : requiredClaims) {
            if (!claims.containsKey(req)) errors.add("MISSING_CLAIM_" + req.toUpperCase());
        }

        return errors.isEmpty() ? ValidationResult.ok() : new ValidationResult(false, errors);
    }

    public static void main(String[] args) {
        long now = System.currentTimeMillis() / 1000;
        long future = now + 3600;
        long past   = now - 3600;
        Set<String> required = Set.of("sub", "role");

        System.out.println("Valid: " + validate(createToken("u1", future, "USER", true), now, required).valid());
        System.out.println("Expired: " + validate(createToken("u1", past, "USER", true), now, required).errors());
        System.out.println("BadSig: " + validate(createToken("u1", future, "USER", false), now, required).errors());
    }
}

