import java.util.*;

public class Q5 {

    static Map<String, String> sessions = new HashMap<>();
    static final Set<String> SAFE_METHODS = Set.of("GET", "HEAD", "OPTIONS");

    static String createSession(String sessionId) {
        String token = UUID.randomUUID().toString();
        sessions.put(sessionId, token);
        return token;
    }

    static boolean validateRequest(String sessionId, String method, String submittedToken) {
        if (SAFE_METHODS.contains(method.toUpperCase())) return true; // safe method, no CSRF check
        String expected = sessions.get(sessionId);
        if (expected == null || submittedToken == null) return false;
        return expected.equals(submittedToken); // constant-time: Arrays.equals(expected.getBytes(), submittedToken.getBytes())
    }

    public static void main(String[] args) {
        String token = createSession("sess-001");
        System.out.println("Token generated: " + (token.length() == 36));
        System.out.println("GET: " + validateRequest("sess-001", "GET", null));
        System.out.println("POST valid: " + validateRequest("sess-001", "POST", token));
        System.out.println("POST invalid: " + validateRequest("sess-001", "POST", "attacker-token"));
        System.out.println("POST missing: " + validateRequest("sess-001", "POST", null));
    }
}

