import java.util.concurrent.*;

public class Q7 {

    static final ThreadLocal<String> SECURITY_CTX = new ThreadLocal<>();

    static String getCurrentUser() { return SECURITY_CTX.get(); }
    static void setCurrentUser(String user) { SECURITY_CTX.set(user); }
    static void clearContext() { SECURITY_CTX.remove(); }

    static Runnable wrapWithContext(Runnable task) {
        String capturedUser = SECURITY_CTX.get(); // capture BEFORE submitting to pool
        return () -> {
            SECURITY_CTX.set(capturedUser);   // restore in async thread
            try {
                task.run();
            } finally {
                SECURITY_CTX.remove();         // always clean up pooled thread
            }
        };
    }

    public static void main(String[] args) throws Exception {
        setCurrentUser("alice");
        System.out.println("Main thread user: " + getCurrentUser());

        ExecutorService pool = Executors.newSingleThreadExecutor();

        Future<?> f1 = pool.submit(() ->
            System.out.println("Async without wrap: " + getCurrentUser()));
        f1.get();

        Future<?> f2 = pool.submit(wrapWithContext(() ->
            System.out.println("Async with wrap: " + getCurrentUser())));
        f2.get();

        pool.shutdown();
        clearContext();
    }
}
